{
  "title": "संदर्भ बजट",
  "group": "टोकन प्रबंधन",
  "options": [
    {
      "text": "सूचना को अधिकतम करने के लिए संदर्भ विंडो का 95%+ उपयोग करें"
    },
    {
      "text": "पूरी विंडो भरने के बजाय आउटपुट के लिए पर्याप्त हेडरूम रखें"
    },
    {
      "text": "संदर्भ बजट केवल 32K टोकन से कम मॉडल के लिए मायने रखता है"
    },
    {
      "text": "विंडो से अधिक होने पर मॉडल स्वतः ट्रंकेट हो जाता है"
    }
  ],
  "questionProse": [
    "प्राप्त संदर्भ के साथ RAG प्रॉम्प्ट बनाते समय, संदर्भ बजट के लिए एक अच्छा नियम है:"
  ],
  "explanationProse": [
    "संदर्भ विंडो **इनपुट और आउटपुट** के बीच साझा होती है। यदि आप इनपुट के लिए 90% उपयोग करते हैं, तो मॉडल के पास प्रतिक्रिया उत्पन्न करने के लिए केवल 10% विंडो बचती है — जिससे अक्सर आउटपुट कट जाता है या घट जाता है।\n\n    एक उचित अनुमान: पहले अपनी अपेक्षित आउटपुट आकार तय करें, फिर अपना इनपुट शेष बजट से नीचे आराम से रखें। कई RAG कार्यों के लिए, इसका मतलब है कि **कुल संदर्भ विंडो के 60–70% से अधिक इनपुट** (सिस्टम प्रॉम्प्ट + इतिहास + प्राप्त संदर्भ) नहीं उपयोग करना। बाकी को जनरेशन और सुरक्षा मार्जिन के लिए छोड़ दें।\n\n    अतिरिक्त रूप से, मॉडल अपनी संदर्भ विंडो के किनारे के पास कम प्रदर्शन करते हैं — समझ और निर्देश‑अनुपालन विंडो भरने पर घटते हैं। 95% पर चलाना तकनीकी रूप से संभव है। लेकिन यह 50% पर चलाने जैसा अनुभव नहीं देता।"
  ]
}
